import{_ as s,o as t,c as r,ag as a}from"./chunks/framework.ETe_P6d1.js";const _="/kaiping-reports/assets/1.DL_XcdNL.jpg",e="/kaiping-reports/assets/2.CY9qTHO4.jpg",o="/kaiping-reports/assets/3.C439Zh2i.jpg",i="/kaiping-reports/assets/4.DAErwXZi.jpg",c="/kaiping-reports/assets/5.CkAamH3h.jpg",n="/kaiping-reports/assets/6.DcFUkuPP.jpg",m="/kaiping-reports/assets/7.CuVpM-Zl.jpg",g="/kaiping-reports/assets/8.BOxr3BYY.jpg",l="/kaiping-reports/assets/9.BJ3GFQ5_.jpg",d="/kaiping-reports/assets/10.C7WHHmX0.jpg",D=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reports/胡马江南/开平侨乡地域建筑调研报告.md","filePath":"reports/胡马江南/开平侨乡地域建筑调研报告.md"}'),k={name:"reports/胡马江南/开平侨乡地域建筑调研报告.md"};function f(P,p,u,S,T,j){return t(),r("div",null,[...p[0]||(p[0]=[a('<p>开平侨乡地域建筑调研报告</p><p>摘要</p><p>本次调研以开平立园、仓东村、塘口墟及赤坎古镇为实地研究对象，，围绕建筑群体空间组织、单体平面形制、立面装饰语言与结构构造细部展开系统比较。研究通过对传统乡土聚落与近代侨宅园林、乡村墟市建筑与城镇商业骑楼的对照分析，梳理开平近代建筑在空间秩序生成、平面功能演进、立面风格转译中的具体特征，阐释中西建筑语汇在岭南地域气候与生活方式下的适配机制，总结侨乡建筑独有的形态规律与营造智慧，为近代岭南建筑空间与风格研究提供扎实的现场实证与理论参照。</p><p>关键词</p><p>开平侨乡建筑；空间秩序；中西建筑语汇；构造细部；岭南近代建筑</p><p>一、空间组织与场所肌理的形制差异</p><p>仓东村传统聚落与立园私家侨宅园林，分别代表开平乡土建筑发展的两个重要阶段，二者在整体布局、轴线关系、空间尺度与功能组织上形成系统性差异，清晰呈现出岭南民居从宗族聚居模式向近代个体人居模式的形态转变。</p><p>仓东村延续岭南广府地区典型的梳式布局体系，村落肌理高度规整且秩序严谨。建筑沿南北向巷道平行排布，巷道窄而笔直，既承担交通功能，也构成村落通风廊道。宗祠位于村落几何中心与视觉制高点，体量突出、形制完整，成为全村空间组织的核心，周边民居严格遵循等级秩序均匀分布，无明显体量差异。单体建筑以三间两廊为基本形制，砖木混合结构，硬山屋顶搭配镬耳山墙，青瓦屋面坡度平缓，适应岭南多雨与强日照气候。平面布局以内向型天井为中心，堂屋居中，两侧厢房对称布置，功能复合且划分简洁，采光、通风与排水均围绕天井展开，空间封闭内敛，尺度亲切宜人，整体呈现出以宗族秩序为核心、以农耕生活为基础的均质化空间特征。</p><p><img src="'+_+'" alt="图1"></p><p>立园则完全跳出传统聚落的布局框架，采用西式轴线构图与中式园林造景相结合的复合空间组织方式。园区以一条明确的主轴线贯穿别墅区与园林区，建筑依轴线错落布置，形成收放有序、层次分明的空间序列。主体别墅采用钢筋混凝土与砖石混合结构，突破传统砖木结构的跨度与层高限制，建筑体量舒展、立面层次丰富。平面功能实现明确细分，设置独立的会客室、起居室、卧室与书房，动线清晰、公私分区明确，取代了传统民居功能混杂的布局方式。园林部分结合自然地形布置水体、花坛与亭廊，空间开合交替，通透开敞，连廊与景墙灵活分隔空间，既保证私密性，又强化建筑与环境的渗透关系。整体空间外向舒展、尺度开阔，强调居住舒适度与审美体验，呈现出以个体生活为中心的近代化人居空间特征。</p><p><img src="'+e+'" alt="2"></p><p><img src="'+o+'" alt="3"></p><p>二、中西建筑元素的融合表达与细部构造</p><p>赤坎古镇骑楼街区与塘口墟乡土建筑群，集中体现了开平建筑中西融合的两种典型路径，二者在立面风格、装饰构件、结构做法与材料运用上差异显著，构成风格鲜明、细节丰富的建筑形态体系。</p><p>赤坎古镇作为近代区域性商业中心，骑楼建筑呈现出整体性、体系化的中西融合特征，风格统一且装饰精致。沿街建筑底层形成连续贯通的骑楼廊道，采用罗马拱券与古典柱式构成立面骨架，柱身比例严谨，拱券曲线流畅，形成强烈的韵律感。二层外立面为建筑装饰重点，大量运用巴洛克式涡卷、花卉浮雕、线脚分层与彩色玻璃花窗，檐口、腰线、窗套装饰繁复细腻，西式美学特征突出。建筑主体结构仍沿用岭南传统砖木体系，青砖墙体厚重密实，双层屋面与通风空腔有效隔热防潮，充分适应岭南湿热气候。骑楼廊道兼具遮阳、避雨与商业通行功能，西式立面形制与本土构造逻辑、气候适应性深度结合，形成兼具商业展示性与地域实用性的近代城镇建筑风貌。</p><p><img src="'+i+'" alt="4"></p><p><img src="'+c+'" alt="5"></p><p>塘口墟建筑以传统民居与防御性碉楼为主，中西融合呈现出碎片化、实用性的民间特征，风格质朴、以功能为先。碉楼为墟镇核心建筑，采用夯土、青砖与石材混合砌筑，墙体坚厚、开窗狭小，整体形制完全服务于防御需求。建筑细部选择性引入西式构件，窗洞外侧加装铸铁雕花栏杆，混凝土窗套饰以简洁西式线脚，顶部瞭望亭采用简化的穹顶与柱廊造型，强化瞭望与防御性能。普通民居则基本保留岭南传统形制，平面布局、结构体系与屋面做法均无明显改动，仅在门头、栏杆、檐口等局部位置点缀少量西式装饰纹样，材料与工艺本土化特征显著。整体而言，西式元素并非风格主导，而是作为功能性构件与装饰补充嵌入乡土建筑体系，形成朴素务实、因地制宜的民间融合形态。</p><p><img src="'+n+'" alt="6"></p><p><img src="'+m+'" alt="7"></p><p>三、建筑形态演进的深层辨析</p><p>开平各类建筑的形态差异与风格演变，并非外在形式的随机叠加，而是地域生活方式、建造技术与审美观念共同作用的必然结果，其核心始终围绕功能适配与地域适应展开。传统聚落的规整空间与均质形制，源于宗族社会的集体生活模式，对称布局、等级秩序与内向型空间，既是礼制观念的体现，也是适配农耕生产与集体聚居的最优选择；近代侨宅的灵活空间与功能细分，则对应着侨民生活方式的近代化转型，开阔尺度、独立分区与景观渗透，本质上是对舒适人居与个体审美需求的回应。</p><p><img src="'+g+'" alt="8"></p><p>中西建筑语汇的融合同样遵循功能优先的原则，呈现出高度的本土化适配性。赤坎骑楼的西式立面与拱券廊道，适配商业建筑的展示性与公共性需求；塘口碉楼的西式金属构件与混凝土构造，则服务于防御安全与结构耐久。无论融合方式如何差异，所有建筑均坚守岭南营造的核心技术逻辑，天井通风、冷巷导风、双层隔热、坡屋顶排水等气候适应性构造贯穿始终，西式材料、构件与风格始终服务于本土功能，从未脱离地域环境与使用需求，形成了形式与功能高度统一的建筑形态逻辑。</p><p><img src="'+l+'" alt="9"></p><p><img src="'+d+'" alt="图10"></p><p>四、结论</p><p>开平立园、仓东村、塘口墟与赤坎古镇四类建筑，以空间秩序与中西融合为两条核心脉络，完整呈现了岭南近代侨乡建筑的形态演进与营造特征。仓东村与立园的空间对照，揭示了从宗族集体空间到近代个体空间的演进路径，布局方式、尺度关系与功能组织的系统性调整，塑造了截然不同的空间体验与场所特质。赤坎古镇与塘口墟的细部对比，展现了体系化风格融合与实用性构件融合两种形态，立面装饰、结构构造与材料运用的差异化处理，构成了多元并存的跨文化建筑表达。</p><p>开平侨乡建筑的核心价值，在于其立足本土营造传统，以功能与气候为根本，实现了空间形态的近代化升级与外来建筑文化的本土化转译。其严谨的空间组织逻辑、精致的建筑构造细部与灵活的风格融合方式，不仅是岭南近代建筑发展的重要实物见证，也为地域建筑创作、传统形制转译与跨文化风格融合研究，提供了极具参考价值的实践样本与理论依据。</p><p>参考文献</p><p>[1] 陆元鼎. 岭南新建筑的特征及其地域风格的创造. ,2005.</p><p>[2] 甄静文. <a href="./abstract.html?v=lLcTIqQqO-3CeyrKvTNzmPyE3DzogbopFHLc--nLYH8eufbFDuFhe9P_F1EuKShrzL7f2EJdwv4dYPwwyc-LE4JrmV2PDYIdOOSoxBTKRD-UQAQS99SHpzWYCWPLcPPWGv3uKhxfI7SQCrz2jxSqgHYfz8O_zMKSD-nUsNldAy2rgkT6vGmI-A==&amp;uniplatform=NZKPT&amp;language=CHS">开平碉楼的装饰艺术与材料应用研究</a> 2021</p><p>[3] 潘谷西. 中国建筑史(第七版)[M]. 北京:中国建筑工业出版社,2015.</p><p>[4] 陈志华. 外国建筑史(19世纪末叶以前)(第四版)[M]. 北京:中国建筑工业出版社,2010.</p><p>[5] 汤国华. 岭南骑楼建筑的地域适应性研究[J]. 建筑学报,2008(06):82-86.</p><p>[6] 李长杰. 广东侨乡中西合璧建筑的装饰语言与空间形态[J]. 装饰,2021(03):116-119.</p><p>[7] 肖旻. 开平侨乡园林建筑的空间形制与文化表征[J]. 南方建筑,2016</p>',37)])])}const h=s(k,[["render",f]]);export{D as __pageData,h as default};
